async function runAgentLoop(messages, tools, maxIterations = 20) {
  for (let i = 0; i < maxIterations; i++) {
    try {
      const response = await claude.messages.create({ messages, tools, model: 'claude-sonnet-4-6' });

      if (response.stop_reason === 'end_turn') {
        return { done: true, result: response };
      }

      if (response.stop_reason === 'tool_use') {
        const toolCall = response.content[0];
        const result = await executeWithTimeout(toolCall, 30000);
        messages.push({ role: 'user', content: result });
        continue;
