// Coordinator delegates to specialized subagents
async function coordinatorAgent(userRequest) {
  const plan = await claude.messages.create({
    messages: [{ role: 'user', content: `Analyze this request and create a plan: ${userRequest}` }],
    tools: [{ name: 'delegate', description: 'Delegate to subagent', input_schema: { type: 'object', properties: { task: { type: 'string' }, agent_type: { type: 'string' } } } }]
  });

  const delegation = JSON.parse(plan.content[0].text);

  // Run subagents in parallel
  const subagentTasks = delegation.tasks.map(task => 
    runSubagent(task.agent_type, task.instructions)
  );

  const results = await Promise.all(subagentTasks);
  return synthesizeResults(results);
}

