async function routeWithConfidence(request) {
  const analysis = await claude.messages.create({
    messages: [{ role: 'user', content: `Analyze confidence for: ${request}` }],
    tools: [{ name: 'assess_confidence', ... }]
  });

  const { confidence, routing } = JSON.parse(analysis.content[0].text);

  if (confidence < 0.7) {
    return escalateToHuman(request, 'low_confidence');
  }

  if (routing === 'specialist') {
    return delegateToSpecialist(request);
  }

  return runStandardAgent(request);
}

class Coordinator {
  async handle(userRequest) {
    // Analyze and decompose the request
    const plan = await this.createPlan(userRequest);

    // Delegate to appropriate subagents
    const tasks = plan.subagents.map(s => this.delegate(s));
    const results = await Promise.all(tasks);

    // Aggregate and synthesize
    return this.synthesize(results);
  }

  async createPlan(request) {
    // Use Claude to break down the request
    return claude.messages.create({
      messages: [{ role: 'user', content: `Create execution plan: ${request}` }]
    });
  }
}

