async function runWithErrorHandling(subagentFn, fallback) {
  try {
    return await subagentFn();
  } catch (error) {
    if (error.type === 'timeout') {
      // Return partial results or fallback
      return fallback({ timeout: true, partialResults: error.partial });
    }
    if (error.type === 'invalid_output') {
      // Retry with corrected prompt
      return retryWithCorrection(subagentFn, error.details);
    }
    throw error; // Unknown error, propagate
  }
}

