// Enforce tool sequencing programmatically
class ToolOrchestrator {
  constructor() {
    this.completedTools = new Set();
    this.toolGraph = {
      'get_customer': [],
      'lookup_order': ['get_customer'],
      'process_refund': ['get_customer', 'lookup_order']
    };
  }

  async execute(toolName, args) {
    const required = this.toolGraph[toolName] || [];
    const missing = required.filter(t => !this.completedTools.has(t));

    if (missing.length > 0) {
      throw new Error(`Must call ${missing.join(', ')} first`);
    }

    const result = await this.callTool(toolName, args);
    this.completedTools.add(toolName);
    return result;
  }
}

