async function getOrder(orderId) {
  // Validate input
  if (!orderId || !orderId.match(/^ORD-\\d+$/)) {
    return {
      isError: true,
      code: 'INVALID_ORDER_ID',
      message: 'Order ID must be in format ORD-XXXXX',
      retryable: false
    };
  }

  try {
    const order = await db.orders.findOne({ orderId });
    if (!order) {
      return {
        isError: true,
        code: 'ORDER_NOT_FOUND',
        message: `Order ${orderId} not found`,
        retryable: false
      };
    }
    return { order };
  } catch (error) {
    if (error.code === 'DB_TIMEOUT') {
      return {
        isError: true,
        code: 'DATABASE_ERROR',
        message: 'Database temporarily unavailable',
        retryable: true
      };
    }
    throw error;
  }
}

