    properties: {
      account_id: { type: 'string' },
      page: { type: 'number', default: 1 },
      per_page: { type: 'number', default: 20, maximum: 100 }
    }
  },
  async execute({ account_id, page, per_page }) {
    const [transactions, total] = await db.transactions.findAndCountAll({
      where: { account_id },
      limit: per_page,
      offset: (page - 1) * per_page
    });

    return {
      transactions,
      pagination: {
        page,
        per_page,
        total,
        total_pages: Math.ceil(total / per_page),
        has_next: page * per_page < total
      }
    };
  }
});

