async function extractWithRetry(text, maxRetries = 3) {
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const result = await claude.messages.create({
        messages: [{ role: 'user', content: text }],
        tools: [extract_order_schema]
      });

      const output = parseToolCall(result);
      validateSchema(output); // Throws if invalid
      return output;

    } catch (error) {
      if (attempt === maxRetries) throw error;

      // Retry with correction
      await claude.messages.create({
        messages: [
          { role: 'user', content: text },
          { role: 'user', content: `Invalid output: ${error.message}. Please correct.` }
        ],
        tools: [extract_order_schema]
      });
    }
  }
}

