async function progressiveSummarizer(conversation, threshold = 0.7) {
  const currentTokens = countTokens(conversation);
  const limit = getContextLimit();

  if (currentTokens / limit < threshold) {
    return conversation; // No summarization needed
  }

  // Summarize older messages
  const { recent, older } = splitConversation(conversation);
  const summary = await claude.messages.create({
    messages: [
      { role: 'user', content: `Summarize this conversation, preserving key facts: ${older}` }
    ]
  });

  return [...summary, ...recent];
}

