// Budget tokens before each API call
function budgetTokens(request) {
  const budget = {
    systemPrompt: 2000,
    toolDefs: calculateTokens(toolDefinitions),
    history: calculateTokens(messageHistory),
    maxResponse: request.maxTokens || 1024
  };

  const total = Object.values(budget).reduce((a, b) => a + b, 0);
  const limit = getModelLimit(request.model);

  if (total > limit * 0.9) {
    throw new Error('Context would exceed limit');
  }

  return budget;
}

